import{f as a,o as s,c as d,a2 as n}from"./chunks/framework.DHYrF-q6.js";const c=JSON.parse('{"title":"实战案例：AI 智能客服从 0 到 1 全流程","description":"","frontmatter":{},"headers":[],"relativePath":"ai-product-manager/case-study.md","filePath":"ai-product-manager/case-study.md","lastUpdated":1781090818000}'),r={name:"ai-product-manager/case-study.md"};function e(o,t,l,i,p,h){return s(),d("div",null,[...t[0]||(t[0]=[n(`<h1 id="实战案例-ai-智能客服从-0-到-1-全流程" tabindex="-1">实战案例：AI 智能客服从 0 到 1 全流程 <a class="header-anchor" href="#实战案例-ai-智能客服从-0-到-1-全流程" aria-label="Permalink to &quot;实战案例：AI 智能客服从 0 到 1 全流程&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>本章以一个<strong>真实的电商 AI 智能客服项目</strong>为线索，完整呈现 AI PM 从需求验证到上线迭代的全流程工作。每个阶段都附有实际的交付物片段和决策依据——不是理论推演，而是&quot;如果让你重做一遍，你会怎么做&quot;级别的还原。</p><div class="tip custom-block"><p class="custom-block-title">为什么选智能客服？</p><p>智能客服是 AI PM 最经典的入门场景——技术成熟度高、ROI 清晰、A/B 测试容易、数据闭环完整。同时也是面试中最有可能被问到的&quot;你做过什么 AI 产品&quot;的场景。读完本章你就能在面试中讲一个完整的端到端案例。</p></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><ul><li><strong>产品</strong>：某电商平台的智能客服系统</li><li><strong>现状</strong>：日均 5000 通在线咨询，50 人客服团队，高峰期排队 &gt; 5 分钟</li><li><strong>目标</strong>：AI 自动处理 40% 的咨询量，人工转接率降低 30%</li><li><strong>时间线</strong>：10 周从立项到全量上线</li></ul><hr><h2 id="一、需求验证阶段-第-1-2-周" tabindex="-1">一、需求验证阶段（第 1-2 周） <a class="header-anchor" href="#一、需求验证阶段-第-1-2-周" aria-label="Permalink to &quot;一、需求验证阶段（第 1-2 周）&quot;">​</a></h2><h3 id="_1-1-第一步-用-ai-适用性矩阵判断" tabindex="-1">1.1 第一步：用 AI 适用性矩阵判断 <a class="header-anchor" href="#_1-1-第一步-用-ai-适用性矩阵判断" aria-label="Permalink to &quot;1.1 第一步：用 AI 适用性矩阵判断&quot;">​</a></h3><p>不是所有需求都适合用 AI 解决。我做的第一件事是用五维评估矩阵打分：</p><table tabindex="0"><thead><tr><th>维度</th><th>评估</th><th>得分</th><th>说明</th></tr></thead><tbody><tr><td><strong>数据可行性</strong></td><td>高</td><td>3</td><td>有 2 年历史对话数据，覆盖 80%+ 咨询场景</td></tr><tr><td><strong>技术可行性</strong></td><td>高</td><td>3</td><td>GPT-4o API + RAG 架构 POC 已跑通</td></tr><tr><td><strong>商业价值</strong></td><td>高</td><td>3</td><td>预计年省 200 万人力成本，ROI &gt; 500%</td></tr><tr><td><strong>用户体验</strong></td><td>高</td><td>3</td><td>用户真实痛点——等待时间太长</td></tr><tr><td><strong>合规风险</strong></td><td>中等</td><td>2</td><td>需做数据脱敏 + 用户知情同意</td></tr></tbody></table><p><strong>总分 14 分 → P0 优先级，干。</strong></p><h3 id="_1-2-第二步-快速-poc-验证可行性" tabindex="-1">1.2 第二步：快速 POC 验证可行性 <a class="header-anchor" href="#_1-2-第二步-快速-poc-验证可行性" aria-label="Permalink to &quot;1.2 第二步：快速 POC 验证可行性&quot;">​</a></h3><p>用 3 天时间搭了一个极简 Demo：</p><ul><li><strong>架构</strong>：GPT-4o API + 100 条历史客服 QA 做 RAG 知识库</li><li><strong>测试方法</strong>：拿出 50 条真实用户咨询，让 AI 回答 + 人工评分</li><li><strong>POC 结果</strong>：</li></ul><table tabindex="0"><thead><tr><th>指标</th><th>POC 结果</th><th>上线最低标准</th></tr></thead><tbody><tr><td>回答准确率</td><td>78%</td><td>85%</td></tr><tr><td>用户满意度评分</td><td>3.2 / 5</td><td>4.0 / 5</td></tr><tr><td>平均响应时间</td><td>2.1 秒</td><td>&lt; 3 秒</td></tr></tbody></table><p><strong>结论</strong>：78% 的准确率虽然不够上线，但方向成立。差距主要来自 RAG 检索不准（知识库文档写得不够结构化）和 Prompt 太粗糙。</p><h3 id="_1-3-第三步-定义上线标准" tabindex="-1">1.3 第三步：定义上线标准 <a class="header-anchor" href="#_1-3-第三步-定义上线标准" aria-label="Permalink to &quot;1.3 第三步：定义上线标准&quot;">​</a></h3><p>在产品还没有的情况下先定义&quot;什么叫成功&quot;，这是 AI PM 最重要的习惯：</p><ul><li><strong>技术指标</strong>：准确率 ≥ 85%，召回率 ≥ 80%</li><li><strong>业务指标</strong>：AI 自动解决率 ≥ 40%，人工转接率下降 ≥ 30%</li><li><strong>体验指标</strong>：用户满意度 ≥ 4.0/5，响应时间 &lt; 3 秒</li><li><strong>上线决策</strong>：灰度 5% 流量跑一周，三项都达标再扩量</li></ul><hr><h2 id="二、mvp-设计阶段-第-3-4-周" tabindex="-1">二、MVP 设计阶段（第 3-4 周） <a class="header-anchor" href="#二、mvp-设计阶段-第-3-4-周" aria-label="Permalink to &quot;二、MVP 设计阶段（第 3-4 周）&quot;">​</a></h2><h3 id="_2-1-定义-ai-的能力边界" tabindex="-1">2.1 定义 AI 的能力边界 <a class="header-anchor" href="#_2-1-定义-ai-的能力边界" aria-label="Permalink to &quot;2.1 定义 AI 的能力边界&quot;">​</a></h3><p>这是最容易被 PM 跳过的步骤——很多人一上来就开始写 Prompt，结果做了三个月发现方向错了。</p><p>我定义了三层能力边界：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ L1: AI 自主处理（目标 40% 咨询量）            │</span></span>
<span class="line"><span>│ • 退货流程咨询 • 物流查询 • 优惠券规则         │</span></span>
<span class="line"><span>│ • 常见商品问题 • 账号操作指导                  │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span>
<span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ L2: AI 辅助 + 人工确认（目标 25% 咨询量）       │</span></span>
<span class="line"><span>│ • 复杂退换货（多商品多订单）                    │</span></span>
<span class="line"><span>│ • 金额相关的投诉（需确认金额）                   │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span>
<span class="line"><span>┌────────────────────────────────────────────┐</span></span>
<span class="line"><span>│ L3: 直接转人工（目标 35% 咨询量）              │</span></span>
<span class="line"><span>│ • 情绪激动用户（检测到负面情绪关键词）           │</span></span>
<span class="line"><span>│ • 涉及赔偿/举报/法律风险                       │</span></span>
<span class="line"><span>│ • AI 置信度 &lt; 80%                            │</span></span>
<span class="line"><span>└────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><h3 id="_2-2-设计三级降级策略" tabindex="-1">2.2 设计三级降级策略 <a class="header-anchor" href="#_2-2-设计三级降级策略" aria-label="Permalink to &quot;2.2 设计三级降级策略&quot;">​</a></h3><p>AI 产品的降级设计比正常流程设计更重要——因为模型一定会犯错。</p><table tabindex="0"><thead><tr><th>场景</th><th>降级策略</th><th>触发条件</th></tr></thead><tbody><tr><td><strong>模型高置信度（&gt; 95%）</strong></td><td>直接返回 AI 回答</td><td>正常</td></tr><tr><td><strong>模型中置信度（80-95%）</strong></td><td>返回知识库原文 + 标注&quot;以下信息来自帮助中心&quot;</td><td>兜底</td></tr><tr><td><strong>模型低置信度（&lt; 80%）</strong></td><td>转人工 + 提示&quot;正在为您转接人工客服&quot;</td><td>止损</td></tr></tbody></table><h3 id="_2-3-mvp-的功能范围" tabindex="-1">2.3 MVP 的功能范围 <a class="header-anchor" href="#_2-3-mvp-的功能范围" aria-label="Permalink to &quot;2.3 MVP 的功能范围&quot;">​</a></h3><table tabindex="0"><thead><tr><th>包含（MVP）</th><th>不包含（V2）</th></tr></thead><tbody><tr><td>文本问答</td><td>语音/图片问答</td></tr><tr><td>退货、物流、优惠券三大场景</td><td>全品类商品咨询</td></tr><tr><td>RAG 知识库检索</td><td>基于用户画像的个性化推荐</td></tr><tr><td>满意/不满意反馈按钮</td><td>多轮对话深度交互</td></tr><tr><td>转人工兜底</td><td>工单自动创建</td></tr></tbody></table><hr><h2 id="三、数据准备阶段-第-3-5-周" tabindex="-1">三、数据准备阶段（第 3-5 周） <a class="header-anchor" href="#三、数据准备阶段-第-3-5-周" aria-label="Permalink to &quot;三、数据准备阶段（第 3-5 周）&quot;">​</a></h2><h3 id="_3-1-标注规范设计" tabindex="-1">3.1 标注规范设计 <a class="header-anchor" href="#_3-1-标注规范设计" aria-label="Permalink to &quot;3.1 标注规范设计&quot;">​</a></h3><p>这是 AI PM 的核心交付物之一。我为三大场景各设计了一份标注规范。以&quot;退货退款&quot;场景为例：</p><details class="details custom-block"><summary>退货退款场景标注规范（节选）</summary><p><strong>标签体系</strong></p><table tabindex="0"><thead><tr><th>标签</th><th>定义</th><th>示例</th></tr></thead><tbody><tr><td><code>return_policy</code></td><td>询问退货政策/流程</td><td>&quot;怎么退货？&quot;&quot;七天无理由怎么算？&quot;</td></tr><tr><td><code>return_progress</code></td><td>查询退货进度</td><td>&quot;我的退款什么时候到？&quot;&quot;退货快递收到了吗？&quot;</td></tr><tr><td><code>return_exception</code></td><td>退货异常/投诉</td><td>&quot;退货被拒绝了&quot;&quot;为什么扣了我的运费？&quot;</td></tr><tr><td><code>exchange_request</code></td><td>换货请求</td><td>&quot;想换个颜色&quot;&quot;尺码不合适换大一号&quot;</td></tr><tr><td><code>other</code></td><td>以上都不属于</td><td>&quot;这个商品什么时候补货？&quot;</td></tr></tbody></table><p><strong>边界 Case 定义</strong></p><table tabindex="0"><thead><tr><th>用户输入</th><th>正确标签</th><th>容易误标为</th><th>判别规则</th></tr></thead><tbody><tr><td>&quot;退货太慢了，我要投诉&quot;</td><td><code>return_exception</code></td><td><code>return_progress</code></td><td>有投诉意图优先归 exception</td></tr><tr><td>&quot;退了再买一个，能便宜吗&quot;</td><td><code>return_policy</code></td><td><code>other</code></td><td>退货意图明确，归 policy</td></tr><tr><td>&quot;怎么退不了啊？？？&quot;</td><td><code>return_exception</code></td><td><code>return_policy</code></td><td>包含操作受阻，归 exception</td></tr><tr><td>&quot;收到了，谢谢&quot;</td><td><code>other</code></td><td>-</td><td>无退货相关意图</td></tr></tbody></table><p><strong>质量控制标准</strong></p><ul><li>Kappa 系数 ≥ 0.75（两人标注一致性）</li><li>黄金集准确率 ≥ 95%（100 条标准答案校准）</li></ul></details><h3 id="_3-2-首批数据标注" tabindex="-1">3.2 首批数据标注 <a class="header-anchor" href="#_3-2-首批数据标注" aria-label="Permalink to &quot;3.2 首批数据标注&quot;">​</a></h3><table tabindex="0"><thead><tr><th>环节</th><th>数量</th><th>成本</th><th>周期</th></tr></thead><tbody><tr><td>意图分类（5 类 × 3 场景）</td><td>3000 条</td><td>¥900（0.3 元/条）</td><td>1 周</td></tr><tr><td>问答对（RAG 知识库）</td><td>500 对</td><td>¥500（内部标注）</td><td>1 周</td></tr><tr><td>边界 Case 专项补充</td><td>200 条</td><td>¥100（内部标注）</td><td>2 天</td></tr><tr><td><strong>合计</strong></td><td><strong>3700 条</strong></td><td><strong>¥1,500</strong></td><td><strong>2 周</strong></td></tr></tbody></table><h3 id="_3-3-数据-pipeline-搭建" tabindex="-1">3.3 数据 Pipeline 搭建 <a class="header-anchor" href="#_3-3-数据-pipeline-搭建" aria-label="Permalink to &quot;3.3 数据 Pipeline 搭建&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户咨询 → 实时日志采集 → Kafka → 数据清洗（脱敏+去重+格式化）</span></span>
<span class="line"><span>                                        ↓</span></span>
<span class="line"><span>                                  标注任务分发（LabelStudio）</span></span>
<span class="line"><span>                                        ↓</span></span>
<span class="line"><span>                                  标注审核（Kappa 检验）</span></span>
<span class="line"><span>                                        ↓</span></span>
<span class="line"><span>                                  训练/评测数据集（版本管理 v1.0）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><hr><h2 id="四、模型方案选型-第-4-5-周" tabindex="-1">四、模型方案选型（第 4-5 周） <a class="header-anchor" href="#四、模型方案选型-第-4-5-周" aria-label="Permalink to &quot;四、模型方案选型（第 4-5 周）&quot;">​</a></h2><h3 id="_4-1-方案对比" tabindex="-1">4.1 方案对比 <a class="header-anchor" href="#_4-1-方案对比" aria-label="Permalink to &quot;4.1 方案对比&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方案</th><th>POC 效果</th><th>成本/次</th><th>延迟</th><th>迭代难度</th></tr></thead><tbody><tr><td><strong>A: GPT-4o API + 基础 Prompt</strong></td><td>准确率 78%，用户体验一般</td><td>¥0.05</td><td>~1.5s</td><td>低（改 Prompt 即可）</td></tr><tr><td><strong>B: GPT-4o API + RAG + 优化 Prompt</strong></td><td>准确率 85-88%，回答有依据</td><td>¥0.08</td><td>~1.8s</td><td>中（改 Prompt + 知识库）</td></tr><tr><td><strong>C: 方案 B + 精调小模型</strong></td><td>准确率 90-93%，成本更低</td><td>¥0.02</td><td>~0.3s</td><td>高（需重训）</td></tr></tbody></table><p><strong>选择方案 B 作为 MVP，方案 C 作为 V2 目标。</strong></p><p>理由：</p><ul><li>方案 B 能在 10 周内上线（方案 C 需要额外 6-8 周精调）</li><li>先用方案 B 积累真实数据，为方案 C 提供高质量训练集</li><li>大模型当老师，小模型当打工人——业界性价比最优路径</li></ul><h3 id="_4-2-成本预估" tabindex="-1">4.2 成本预估 <a class="header-anchor" href="#_4-2-成本预估" aria-label="Permalink to &quot;4.2 成本预估&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th>月度成本</th><th>说明</th></tr></thead><tbody><tr><td>GPT-4o API（意图分类 + 答案生成）</td><td>¥1,500</td><td>日均 5000 次 × 30 天 × ¥0.01（仅意图分类用大模型）</td></tr><tr><td>Embedding 检索</td><td>¥200</td><td>知识库检索</td></tr><tr><td>精调小模型推理（V2 阶段）</td><td>¥300</td><td>意图分类下沉到自部署小模型后大幅降本</td></tr><tr><td>知识库维护人力</td><td>¥5,000</td><td>1/4 人力，持续维护</td></tr><tr><td><strong>合计（V1）</strong></td><td><strong>¥6,700/月</strong></td><td>vs 20 个人工客服 ¥167,000/月</td></tr></tbody></table><hr><h2 id="五、prompt-迭代优化-第-5-6-周" tabindex="-1">五、Prompt 迭代优化（第 5-6 周） <a class="header-anchor" href="#五、prompt-迭代优化-第-5-6-周" aria-label="Permalink to &quot;五、Prompt 迭代优化（第 5-6 周）&quot;">​</a></h2><h3 id="_5-1-版本演进" tabindex="-1">5.1 版本演进 <a class="header-anchor" href="#_5-1-版本演进" aria-label="Permalink to &quot;5.1 版本演进&quot;">​</a></h3><p>这是整个项目中最&quot;AI PM&quot;的工作——持续调 Prompt，看 Bad Case，再调 Prompt。</p><p><strong>V1（第 5 周初，准确率 82%）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>你是电商客服助手。请根据用户问题给出回答。</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>问题：模型经常答非所问，有时编造不存在的退货政策。</p><p><strong>V2（第 5 周末，准确率 88%）</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## 角色</span></span>
<span class="line"><span>你是 XX 电商的智能客服助手。友好、专业。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 知识范围</span></span>
<span class="line"><span>只能基于【参考资料】回答问题。</span></span>
<span class="line"><span>如果参考资料中没有答案，必须说&quot;建议您联系人工客服获取准确信息&quot;。</span></span>
<span class="line"><span>严禁编造任何信息。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 参考资料</span></span>
<span class="line"><span>{检索到的帮助中心文档}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p>改进点：加了知识范围约束和 RAG 检索。准确率提升 6 个点。但发现模型在&quot;参考资料里有但是表述不同&quot;的场景下还是会编。</p><p><strong>V3（第 6 周末，准确率 93%）</strong></p><p>在 V2 基础上增加了：</p><ul><li>Few-shot 示例（3 个正确回答 + 2 个&quot;不知道&quot;的正确示范）</li><li>输出格式约束（先给简短答案，再给&quot;I 帮助中心参考链接&quot;）</li><li>敏感词触发规则（检测到&quot;投诉/举报/赔偿&quot;→强制转人工）</li></ul><div class="tip custom-block"><p class="custom-block-title">迭代经验</p><p>每一次 Prompt 迭代都应该回答三个问题：</p><ol><li>这版改了哪些 Bad Case？（不是感觉，是具体哪类 Case）</li><li>有没有引入新的问题？（V3 的&quot;不知道&quot;示范导致模型在某些本该能回答的场景也说不知道——矫枉过正了）</li><li>下一步的优化假设是什么？</li></ol></div><h3 id="_5-2-bad-case-分析——ai-pm-最重要的日常" tabindex="-1">5.2 Bad Case 分析——AI PM 最重要的日常 <a class="header-anchor" href="#_5-2-bad-case-分析——ai-pm-最重要的日常" aria-label="Permalink to &quot;5.2 Bad Case 分析——AI PM 最重要的日常&quot;">​</a></h3><p>每周五下午固定流程：</p><ol><li>从上一周的线上日志中抽取 100 条 AI 回答</li><li>人工标注每个回答的质量：✅ 好 / ⚠️ 可接受 / ❌ 差</li><li>对 ❌ 的 Case 分类归因</li></ol><table tabindex="0"><thead><tr><th>错误类型</th><th>占比</th><th>根因</th><th>解决方案</th></tr></thead><tbody><tr><td>检索到的文档不对</td><td>35%</td><td>知识库文档标题不匹配用户表达</td><td>优化文档标题 + 查询改写</td></tr><tr><td>答案是错的</td><td>25%</td><td>模型在&quot;不够确定&quot;时也给答案</td><td>提高&quot;不知道&quot;触发的置信度阈值</td></tr><tr><td>答案太啰嗦</td><td>20%</td><td>Prompt 没约束输出长度</td><td>加&quot;回答不超过 3 句话&quot;</td></tr><tr><td>转人工太激进</td><td>20%</td><td>敏感词检测过于宽泛</td><td>精准化敏感词列表</td></tr></tbody></table><hr><h2 id="六、灰度上线与-a-b-测试-第-7-9-周" tabindex="-1">六、灰度上线与 A/B 测试（第 7-9 周） <a class="header-anchor" href="#六、灰度上线与-a-b-测试-第-7-9-周" aria-label="Permalink to &quot;六、灰度上线与 A/B 测试（第 7-9 周）&quot;">​</a></h2><h3 id="_6-1-灰度策略" tabindex="-1">6.1 灰度策略 <a class="header-anchor" href="#_6-1-灰度策略" aria-label="Permalink to &quot;6.1 灰度策略&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>流量比例</th><th>持续天数</th><th>放量条件</th></tr></thead><tbody><tr><td>内部灰度</td><td>仅内部账号</td><td>3 天</td><td>无明显 Bug</td></tr><tr><td>小流量</td><td>5% 用户</td><td>5 天</td><td>核心指标不劣于对照组</td></tr><tr><td>中流量</td><td>20% 用户</td><td>5 天</td><td>继续观察稳定性</td></tr><tr><td>全量</td><td>100%</td><td>持续</td><td>—</td></tr></tbody></table><h3 id="_6-2-a-b-测试实验设计" tabindex="-1">6.2 A/B 测试实验设计 <a class="header-anchor" href="#_6-2-a-b-测试实验设计" aria-label="Permalink to &quot;6.2 A/B 测试实验设计&quot;">​</a></h3><ul><li><strong>实验组</strong>：用户咨询时先由 AI 回答，不满意转人工</li><li><strong>对照组</strong>：保持纯人工客服</li><li><strong>样本量计算</strong>：预期人工转接率从 95% 降到 60%，α=0.05，power=0.8，每组需要约 800 次咨询。5% 流量 3 天能跑够。</li></ul><h3 id="_6-3-a-b-测试结果-小流量-5-×-5-天" tabindex="-1">6.3 A/B 测试结果（小流量 5% × 5 天） <a class="header-anchor" href="#_6-3-a-b-测试结果-小流量-5-×-5-天" aria-label="Permalink to &quot;6.3 A/B 测试结果（小流量 5% × 5 天）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>指标</th><th>对照组</th><th>实验组</th><th>变化</th><th>显著性</th></tr></thead><tbody><tr><td>人工转接率</td><td>95.0%</td><td>57.2%</td><td><strong>-39.8%</strong></td><td>p &lt; 0.001 ✅</td></tr><tr><td>AI 自动解决率</td><td>—</td><td>42.8%</td><td>—</td><td>—</td></tr><tr><td>用户满意度</td><td>4.1</td><td>3.9</td><td>-0.2</td><td>p = 0.08（不显著）</td></tr><tr><td>平均响应时间</td><td>120s</td><td>2.3s</td><td><strong>-98%</strong></td><td>p &lt; 0.001 ✅</td></tr><tr><td>客服人效（咨询/人/天）</td><td>100</td><td>175</td><td><strong>+75%</strong></td><td>p &lt; 0.001 ✅</td></tr></tbody></table><p><strong>结论</strong>：核心指标全面正向，用户满意度轻微下降但不显著（可能是对新交互模式的不适应）。通过放量评审，进入中流量阶段。</p><h3 id="_6-4-灰度中踩的坑" tabindex="-1">6.4 灰度中踩的坑 <a class="header-anchor" href="#_6-4-灰度中踩的坑" aria-label="Permalink to &quot;6.4 灰度中踩的坑&quot;">​</a></h3><ol><li><strong>&quot;谢谢&quot;和&quot;好的&quot;被 AI 当成新问题</strong>：用户说&quot;谢谢&quot;之后 AI 又开始重复回答。修复：增加对话终结识别。</li><li><strong>高峰期 API 超时</strong>：晚 8-10 点 GPT-4o API 延迟从 1.5s 飙升到 8s。修复：加超时降级（&gt;5s 直接转知识库兜底回答）。</li><li><strong>Android 端表情包异常</strong>：用户发微信自带表情包时，API 收到的是乱码。修复：预处理阶段过滤非文本 Unicode 字符。</li></ol><hr><h2 id="七、数据闭环与持续优化-第-10-周起" tabindex="-1">七、数据闭环与持续优化（第 10 周起） <a class="header-anchor" href="#七、数据闭环与持续优化-第-10-周起" aria-label="Permalink to &quot;七、数据闭环与持续优化（第 10 周起）&quot;">​</a></h2><h3 id="_7-1-数据漂移监控" tabindex="-1">7.1 数据漂移监控 <a class="header-anchor" href="#_7-1-数据漂移监控" aria-label="Permalink to &quot;7.1 数据漂移监控&quot;">​</a></h3><p>上线第 3 周，发现 AI 自动解决率从 43% 降到了 38%。排查流程：</p><ol><li><strong>确认不是波动</strong>：连续 5 天下降，统计检验显著 → 是真的下降了</li><li><strong>看数据分布</strong>：双十一大促开始后，&quot;退货退款&quot;类咨询占比从 30% 飙到 55%</li><li><strong>根因定位</strong>：退货场景的复杂 Case（多商品多订单）比例从 10% 升到 25%，这些 Case 准确率只有 72%</li><li><strong>解决</strong>：紧急补充 200 条退货复杂场景的 QA 对到知识库 + 微调意图分类模型 → 自动解决率恢复到 41%</li></ol><h3 id="_7-2-v2-阶段的三个优化方向" tabindex="-1">7.2 V2 阶段的三个优化方向 <a class="header-anchor" href="#_7-2-v2-阶段的三个优化方向" aria-label="Permalink to &quot;7.2 V2 阶段的三个优化方向&quot;">​</a></h3><table tabindex="0"><thead><tr><th>优化方向</th><th>方法</th><th>预期收益</th><th>优先级</th></tr></thead><tbody><tr><td><strong>意图分类下沉到精调小模型</strong></td><td>用积累的 5000 条真实标注数据微调 BERT → 意图分类推理成本降低 95%</td><td>月省 ¥1,200</td><td>P0</td></tr><tr><td><strong>多轮对话能力</strong></td><td>引入对话状态追踪——记住用户上一轮说的是哪个订单、什么商品</td><td>用户满意度 +0.3</td><td>P1</td></tr><tr><td><strong>个性化推荐</strong></td><td>基于用户画像和购买历史，推荐相关帮助文档</td><td>自动解决率 +5%</td><td>P2</td></tr></tbody></table><hr><h2 id="八、面试追问合集" tabindex="-1">八、面试追问合集 <a class="header-anchor" href="#八、面试追问合集" aria-label="Permalink to &quot;八、面试追问合集&quot;">​</a></h2><h3 id="q1-这个项目中你最大的决策失误是什么" tabindex="-1">Q1: 这个项目中你最大的决策失误是什么？ <a class="header-anchor" href="#q1-这个项目中你最大的决策失误是什么" aria-label="Permalink to &quot;Q1: 这个项目中你最大的决策失误是什么？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>我选方案 B（GPT-4o + RAG）是对的，但低估了 RAG 检索质量对产品体验的影响。</p><p>最初我用了最简单的向量检索——Embedding + 余弦相似度。上线后发现一个尴尬的问题：用户搜&quot;退货&quot;时，检索到的文档是&quot;如何发起退货&quot;（正确），但用户搜&quot;退款&quot;时，由于&quot;退款&quot;的操作入口在&quot;退货&quot;流程里，检索返回的是&quot;如何查看退款进度&quot;——但用户其实还不知道怎么退款。</p><p>这是典型的&quot;用户表达 ≠ 系统文档标题&quot;问题。我犯了所有 AI PM 第一次做 RAG 都会犯的错误——<strong>高估了向量检索的能力，低估了查询改写的必要性</strong>。</p><p>后来加了查询改写模块：用户输入&quot;我的退款什么时候到&quot;→ 改写为&quot;退货进度查询+退款到账时间&quot;→ 再用改写后的查询去检索。准确率提了 8 个点。</p><p>如果重来一次，我会在 POC 阶段就做&quot;查询改写对检索质量的影响&quot;专项测试，而不是等到上线后才补救。</p></details><h3 id="q2-你怎么说服管理层投入资源做这个项目" tabindex="-1">Q2: 你怎么说服管理层投入资源做这个项目？ <a class="header-anchor" href="#q2-你怎么说服管理层投入资源做这个项目" aria-label="Permalink to &quot;Q2: 你怎么说服管理层投入资源做这个项目？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>我没有讲技术方案，直接算了一笔经济账：</p><p>&quot;我们 50 个客服，保守估计 40% 的咨询量是标准化问题（退货流程、物流查询、优惠券规则），这些不需要人类的判断力。如果 AI 能处理这 40%，相当于省掉 20 个客服的人力。20 个客服的年成本是 200 万。AI 方案的成本是多少？GPT-4o API 每月 1500 块，加上检索、维护，每月不到 7000 块，一年 8 万。200 万 vs 8 万——这是一笔不需要犹豫的投资。&quot;</p><p>然后我补了一句：&quot;最重要的是，我们不是花 200 万赌 AI 能不能行——我们可以先用 5 万块做 POC，两周出 Demo。Demo 跑通了再决策要不要投全量。&quot;</p><p>这两句话的效果：第一句给信心（ROI 高），第二句给安全感（试错成本低）。管理层当场就批了。</p></details><h3 id="q3-上线一年后回头看-你最大的认知变化是什么" tabindex="-1">Q3: 上线一年后回头看，你最大的认知变化是什么？ <a class="header-anchor" href="#q3-上线一年后回头看-你最大的认知变化是什么" aria-label="Permalink to &quot;Q3: 上线一年后回头看，你最大的认知变化是什么？&quot;">​</a></h3><details class="details custom-block"><summary>答案</summary><p>最大的认知变化是：<strong>AI 产品的壁垒不是模型能力，是数据和流程的深度耦合</strong>。</p><p>刚做这个项目时，我觉得&quot;接个 GPT API + 写个 Prompt&quot;就是 AI 产品了。一年后我明白那只是 Demo。</p><p>真正的壁垒是：</p><ol><li>我们积累了 50 万条真实对话数据 + 3 万条高质量人工标注——这个数据集的价值远超任何公开数据集，因为它完全贴合我们的业务场景。</li><li>标注规范沉淀了 200+ 条边界 Case 定义——这是团队知识的结晶，新标注员一周就能上手。</li><li>Prompt 经历了 47 次迭代——每一次迭代都不是拍脑袋，而是基于 Bad Case 的精确分析。</li><li>数据闭环跑通后——用户反馈 → Bad Case 分析 → 知识库更新 → 模型再训练 → 效果验证——这个飞轮一旦转起来，竞品拿不走。</li></ol><p>如果我只停留在&quot;写 Prompt&quot;的层面，这个产品上线 3 个月就会被竞品追平。但因为我们在数据和流程上扎得足够深——一年后竞品用同样的 GPT 模型也做不出我们的效果。</p></details><hr><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="./product-design">AI 产品设计</a></li><li><a href="./data-model-management">数据与模型管理</a></li><li><a href="./prompt-engineering">Prompt 工程</a></li><li><a href="./business-commercialization">AI 商业落地与策略</a></li><li><a href="./interview">AI PM 面试高频题</a></li></ul>`,96)])])}const b=a(r,[["render",e]]);export{c as __pageData,b as default};
